mapper.select:
SELECT COUNT(*) FROM VOLUNTEER_RECRUIT
STATUS = #{status}
AND ( TITLE LIKE '%' || #{keyword} || '%' OR CONTENT LIKE '%' || #{keyword} || '%' OR LOCATION LIKE '%' || #{keyword} || '%' )

SELECT * FROM ( SELECT ROWNUM RN, A.* FROM ( SELECT RECRUIT_ID AS recruitId, TITLE AS title, CONTENT AS content, VOLUNTEER_DATE AS volunteerDate, LOCATION AS location, APPLY_DEADLINE AS applyDeadline, CREATE_DATE AS createDate, STATUS AS status, MEMBER_ID AS memberId, THUMBNAIL_IMG AS thumbnailImg FROM VOLUNTEER_RECRUIT
STATUS = #{status}
AND ( TITLE LIKE '%' || #{keyword} || '%' OR CONTENT LIKE '%' || #{keyword} || '%' OR LOCATION LIKE '%' || #{keyword} || '%' )
ORDER BY APPLY_DEADLINE ASC, RECRUIT_ID DESC
ORDER BY RECRUIT_ID DESC
) A ) WHERE RN BETWEEN #{startRow} AND #{endRow}

SELECT COUNT(*)
 FROM VOLUNTEER_APPLY
 WHERE MEMBER_ID = #{memberId}
   AND RECRUIT_ID = #{recruitId}

SELECT COUNT(*)
FROM VOLUNTEER_APPLY
WHERE RECRUIT_ID = #{recruitId}
  AND INTEREST_TYPE = #{interestType}
  AND STATUS = '승인'

SELECT NVL(CAPACITY, 0)
FROM VOLUNTEER_RECRUIT_DETAIL
WHERE RECRUIT_ID = #{recruitId}
  AND INTEREST_TYPE = #{interestType}

mapper.insert:
select SEQ_VOLUNTEER_RECRUIT.NEXTVAL FROM DUAL
INSERT INTO VOLUNTEER_RECRUIT ( RECRUIT_ID, TITLE, CONTENT, VOLUNTEER_DATE, LOCATION, APPLY_DEADLINE, CREATE_DATE, STATUS, MEMBER_ID, THUMBNAIL_IMG
) VALUES( #{recruitId}, #{title}, #{content}, #{volunteerDate, jdbcType=DATE}, #{location}, #{applyDeadline, jdbcType=DATE}, SYSDATE, #{status}, #{memberId}, #{thumbnailImg} )

