UPDATE VOLUNTEER_RECRUIT_DETAIL
SET CAPACITY = #{capacity}
WHERE RECRUIT_ID = #{recruitId}
  AND INTEREST_TYPE = #{interestType}

UPDATE VOLUNTEER_RECRUIT
SET STATUS = '모집마감'
WHERE RECRUIT_ID = #{value}

